target.echo:
#!/bin/bash # requires swt-libs # you may need to set LD_LIBRARY_PATH export LD_LIBRARY_PATH=${swtdir}
FALLBACKJAR="${swtjar}${classp2}"
# using alternatives JARS="";
# as soon as the prerm-bug is fixed in libswt-gtk-3.2-java # add "swt" as firs entry! TRYALT="libswt-3.3-java libswt-3.2-java libswt-3.1-java swt-java"; for a in $TRYALT; do if [ -f /etc/alternatives/$a ]; then #echo "using alternatives: $a" . /etc/alternatives/$a break fi done
if [ "$JARS" = "" ]; then if [ "$FALLBACKJAR" = "" ]; then echo "unable to find a SWT-jar"; exit 1 else JARS=$FALLBACKJAR fi fi
# CLASSPATH #CLASSPATH="${package.installdir.jar}/${package.appname}.jar${path.separator}${swtjar}${classp2}" CLASSPATH="${package.installdir.jar}/${outfile}.jar${path.separator}$JARS";
# sun java #java -cp $CLASSPATH ${package.name}.${package.classname} java -cp $CLASSPATH -Djava.library.path=$LD_LIBRARY_PATH ${package.name}.${classname} "$@"
# gij #gij -cp $CLASSPATH ${package.name}.${classname} "$@"
# jamvm (needs LD_LIBRARY_PATH !!! uncomment it!) #jamvm -cp $CLASSPATH ${package.name}.${classname} "$@"
# sablevm (needs LD_LIBRARY_PATH !!! uncomment it!) #sablevm -p java.library.path=$LD_LIBRARY_PATH --classpath $CLASSPATH ${package.name}.${classname} "$@"
# kaffe #kaffe -cp $CLASSPATH ${package.name}.${classname} "$@"
